import (
	"context"
	"fmt"

	mcpgo "github.com/mark3labs/mcp-go/mcp"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/item"
)

// sensitivityRank maps sensitivity levels to numeric ranks for comparison.
var sensitivityRank = map[string]int{
	"normal":    0,
	"sensitive": 1,
	"private":   2,
}

// AllowedTool checks whether the MCP client (if present) is permitted to call
// the named tool. JWT-authenticated requests (no MCPClientInfo) are always allowed.
func AllowedTool(ctx context.Context, toolName string) *mcpgo.CallToolResult {
	client := auth.GetMCPClient(ctx)
	if client == nil {
		return nil // JWT auth — no restrictions
	}

	// Empty tool list means "all tools allowed"
	if len(client.Tools) == 0 {
		return nil
	}

	for _, t := range client.Tools {
		if t == toolName {
			return nil
		}
	}

	return mcpgo.NewToolResultError(fmt.Sprintf("tool %q not permitted for this API key", toolName))
}

// SensitivityAllowed returns true if the given sensitivity level is within the
// client's maximum. JWT-authenticated requests are unrestricted. Private items
// are NEVER returned via MCP regardless of client configuration.
func SensitivityAllowed(ctx context.Context, sensitivity string) bool {
	// Private items are never returned via MCP
	if sensitivity == "private" {
		return false
	}

	client := auth.GetMCPClient(ctx)
	if client == nil {
		return true // JWT auth — allow everything except private
	}

	maxSensitivity := client.MaxSensitivity
	if maxSensitivity == "" {
		maxSensitivity = "normal"
	}

	return sensitivityRank[sensitivity] <= sensitivityRank[maxSensitivity]
}

// FilterItemsBySensitivity removes items that exceed the client's sensitivity
// limit from a search result.
func FilterItemsBySensitivity(ctx context.Context, result *item.SearchResult) *item.SearchResult {
	filtered := make([]*item.Item, 0, len(result.Items))
	for _, it := range result.Items {
		if SensitivityAllowed(ctx, it.Sensitivity) {
			filtered = append(filtered, it)
		}
	}
	return &item.SearchResult{
		Items:   filtered,
		Total:   len(filtered),
		HasMore: result.HasMore,
	}
}
"},"permission_updates":[]}}

